package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.VariableDeclarator;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.stmt.ReturnStmt;
import java.io.File;
import java.io.IOException;

public class Main {
    public static void main(String[] args) throws IOException {
        String inputFile = "/workspace/code-coverage-api-plugin/ui-tests/src/main/java/io/jenkins/plugins/coverage/util/ChartUtil.java";
        String outputFile = inputFile;

        if (args.length >= 1) {
            inputFile = args[0];
        }
        if (args.length >= 2) {
            outputFile = args[1];
        }

        CompilationUnit cu = StaticJavaParser.parse(new File(inputFile));

        // Remove the import for com.gargoylesoftware.htmlunit.ScriptResult
        cu.getImports().removeIf(importDecl -> 
            importDecl.getNameAsString().equals("com.gargoylesoftware.htmlunit.ScriptResult"));

        // Find and fix all usages of ScriptResult
        cu.findAll(ObjectCreationExpr.class).stream()
            .filter(creation -> creation.getType().asString().equals("ScriptResult"))
            .forEach(creation -> {
                // Get the parent ExpressionStmt or VariableDeclarator
                var parent = creation.getParentNode().orElse(null);

                if (parent instanceof ExpressionStmt) {
                    // This is a standalone expression, remove it
                    ((ExpressionStmt) parent).remove();
                } else if (parent instanceof VariableDeclarator) {
                    // Variable declarator like: ScriptResult scriptResult = new ScriptResult(result);
                    VariableDeclarator varDecl = (VariableDeclarator) parent;

                    // Check if there's a subsequent method call on this variable
                    varDecl.findAncestor(ExpressionStmt.class).ifPresent(exprStmt -> {
                        // Look for subsequent method calls on this variable in the same scope
                        varDecl.getParentNode().ifPresent(scope -> {
                            scope.findAll(MethodCallExpr.class).stream()
                                .filter(method -> method.getScope()
                                    .filter(s -> s.toString().equals(varDecl.getNameAsString()))
                                    .isPresent())
                                .filter(method -> method.getNameAsString().equals("getJavaScriptResult"))
                                .forEach(method -> {
                                    // Replace the method call with just the variable
                                    method.replace(varDecl.getNameAsExpression());
                                });
                        });
                    });

                    // Replace the initializer with just the argument
                    if (!creation.getArguments().isEmpty()) {
                        varDecl.setInitializer(creation.getArgument(0));
                    }

                    // Change the type from ScriptResult to Object
                    varDecl.setType("Object");
                }
            });

        // Fix return statements that use ScriptResult pattern
        cu.findAll(ReturnStmt.class).forEach(returnStmt -> {
            returnStmt.findAll(MethodCallExpr.class).stream()
                .filter(method -> method.getNameAsString().equals("getJavaScriptResult"))
                .forEach(method -> {
                    // Replace method.getJavaScriptResult().toString() with method.toString()
                    var scope = method.getScope().orElse(null);
                    if (scope != null) {
                        method.replace(scope);
                    }
                });
        });

        // Write the modified file
        StaticJavaParser.printer().print(cu, new File(outputFile));

        System.out.println("Transformation complete. Fixed file written to: " + outputFile);
    }
}

